def traced_baseline(values: list[int]) -> dict[str, object]:
    comparisons = 0
    best = None
    for value in values:
        comparisons += 1
        if best is None or value < best: best = value
    assert comparisons == len(values)
    return {"result": best, "comparisons": comparisons}

